mapper.select:
SELECT COUNT(1)
FROM ESS_APPLY_OT
WHERE PERSON_ID = #{personId, jdbcType=VARCHAR}
  AND CPNY_ID = #{cpnyId, jdbcType=VARCHAR}
  AND AFFIRM_FLAG NOT IN ('14014309', '14014310')
  AND TO_CHAR(CONFIRM_FLAG) <> '2'
  AND ACTIVITY = 1
  AND OT_FROM_TIME < TO_DATE(#{otToTime, jdbcType=VARCHAR}, 'YYYY-MM-DD HH24:MI')
  AND OT_TO_TIME > TO_DATE(#{otFromTime, jdbcType=VARCHAR}, 'YYYY-MM-DD HH24:MI')

    AND APPLY_NO <> #{applyNo, jdbcType=VARCHAR}
